create table if not exists users (id bigserial primary key,email varchar(190) unique not null,username varchar(80) unique not null,password_hash text not null,role varchar(30) not null default 'player',email_verified_at timestamp null,email_verification_token varchar(120),remember_token varchar(120),avatar_path text,settings jsonb not null default '{}',banned_until timestamp null,created_at timestamp not null default now(),updated_at timestamp not null default now());
create table if not exists universes (id bigserial primary key,name varchar(120) not null,speed numeric(8,2) not null default 1,fleet_speed numeric(8,2) not null default 1,research_speed numeric(8,2) not null default 1,settings jsonb not null default '{}',created_at timestamp not null default now());
create table if not exists planets (id bigserial primary key,universe_id bigint references universes(id),user_id bigint references users(id),name varchar(120) not null,galaxy int not null,system int not null,slot int not null,temperature_min int default -20,temperature_max int default 60,fields_used int default 0,fields_max int default 220,metal numeric(20,3) default 500,crystal numeric(20,3) default 500,deuterium numeric(20,3) default 0,energy numeric(20,3) default 20,storage_capacity numeric(20,3) default 100000,last_resource_at timestamp not null default now(),theme varchar(80) default 'terran',unique(universe_id,galaxy,system,slot));
create table if not exists planet_buildings (planet_id bigint references planets(id) on delete cascade,type varchar(80) not null,level int not null default 0,primary key(planet_id,type));
create table if not exists build_queue (id bigserial primary key,planet_id bigint references planets(id) on delete cascade,type varchar(80) not null,level int not null,finish_at timestamp not null,completed_at timestamp null,created_at timestamp default now());
create table if not exists researches (user_id bigint references users(id) on delete cascade,type varchar(80) not null,level int not null default 0,primary key(user_id,type));
create table if not exists research_queue (id bigserial primary key,user_id bigint references users(id),planet_id bigint references planets(id),type varchar(80),level int,finish_at timestamp,completed_at timestamp null);
create table if not exists ships (planet_id bigint references planets(id) on delete cascade,type varchar(80) not null,amount bigint not null default 0,primary key(planet_id,type));
create table if not exists fleets (id bigserial primary key,user_id bigint references users(id),planet_id bigint references planets(id),ships jsonb not null,status varchar(30) not null default 'docked');
create table if not exists fleet_movements (id bigserial primary key,user_id bigint references users(id),origin_planet_id bigint references planets(id),target_galaxy int,target_system int,target_slot int,mission varchar(40),ships jsonb not null,depart_at timestamp not null,arrive_at timestamp not null,return_at timestamp null,recalled_at timestamp null,status varchar(40) not null);
create table if not exists alliances (id bigserial primary key,tag varchar(12) unique not null,name varchar(120) not null,description text,created_by bigint references users(id),created_at timestamp default now());
create table if not exists alliance_members (alliance_id bigint references alliances(id) on delete cascade,user_id bigint references users(id) on delete cascade,rank varchar(60) default 'member',permissions jsonb default '{}',joined_at timestamp default now(),primary key(alliance_id,user_id));
create table if not exists combats (id bigserial primary key,universe_id bigint references universes(id),attacker_id bigint references users(id),defender_id bigint references users(id),coordinates varchar(40),result varchar(40),rounds jsonb,created_at timestamp default now());
create table if not exists battle_reports (id bigserial primary key,combat_id bigint references combats(id),user_id bigint references users(id),summary jsonb,read_at timestamp null,created_at timestamp default now());
create table if not exists marketplace_trades (id bigserial primary key,user_id bigint references users(id),offer jsonb not null,request jsonb not null,status varchar(30) default 'open',created_at timestamp default now(),completed_at timestamp null);
create table if not exists messages (id bigserial primary key,sender_id bigint references users(id),recipient_id bigint references users(id),subject varchar(190),body text,read_at timestamp null,created_at timestamp default now());
create table if not exists notifications (id bigserial primary key,user_id bigint references users(id),type varchar(80),payload jsonb not null default '{}',read_at timestamp null,created_at timestamp default now());
create table if not exists achievements (id bigserial primary key,code varchar(80) unique not null,name varchar(120),description text,reward jsonb default '{}');
create table if not exists user_achievements (user_id bigint references users(id),achievement_id bigint references achievements(id),unlocked_at timestamp default now(),primary key(user_id,achievement_id));
create table if not exists premium_transactions (id bigserial primary key,user_id bigint references users(id),kind varchar(60),amount int,metadata jsonb default '{}',created_at timestamp default now());
create index if not exists idx_planets_user on planets(user_id); create index if not exists idx_planets_coords on planets(universe_id,galaxy,system,slot); create index if not exists idx_fleet_arrivals on fleet_movements(status,arrive_at); create index if not exists idx_notifications_user on notifications(user_id,read_at); create index if not exists idx_market_status on marketplace_trades(status,created_at);
